import scala.xml.XML

class ConfigurationService {
  def parseConfig(configXml: String): Map[String, String] = {
    val xml = XML.loadString(configXml)
    val settings = (xml \ "settings").map { setting =>
      (setting \ "@name").text -> (setting \ "@value").text
    }.toMap
    settings
  }
